fn to_base36(n: u64) -> String {
    if n == 0 {
        return "0".to_string();
    }
    let mut digits = Vec::new();
    let mut num = n;
    while num > 0 {
        let rem = num % 36;
        let ch = if rem < 10 {
            (b'0' + rem as u8) as char
        } else {
            (b'A' + (rem - 10) as u8) as char
        };
        digits.push(ch);
        num = num / 36;
    }
    digits.reverse();
    digits.iter().collect()
}

fn solve(n: i64) -> String {
    let n_squared = n * n;
    let hex_str = format!("{:X}", n_squared);
    let n_cubed = n * n * n;
    let base36_str = to_base36(n_cubed as u64);
    format!("{}{}", hex_str, base36_str)
}
